class Solution:
    def longestArithmetic(self, nums):
        n = len(nums)
        # small arrays: true brute force over every subarray and every single index that
        # could be freely rewritten, independent of the run-length bookkeeping below.
        if n <= 11:
            best = 1
            for start in range(n):
                for end in range(start, n):
                    length = end - start + 1
                    if length <= 2:
                        best = max(best, length)
                        continue
                    feasible = False
                    for k in range(start, end + 1):
                        forced = None
                        ok = True
                        for i in range(start, end):
                            if i == k or i + 1 == k:
                                continue
                            dd = nums[i+1] - nums[i]
                            if forced is None:
                                forced = dd
                            elif forced != dd:
                                ok = False
                                break
                        if not ok:
                            continue
                        interior = start < k < end
                        if interior:
                            if (nums[k+1] - nums[k-1]) % 2 != 0:
                                continue
                            d = (nums[k+1] - nums[k-1]) // 2
                            if forced is not None and forced != d:
                                continue
                        feasible = True
                        break
                    if feasible:
                        best = max(best, length)
            return best
        # larger arrays: an independently-structured pass over consecutive gaps that builds
        # a flat list of length candidates (run-length, single-step extension, bridged
        # extension) and takes their maximum, rather than folding everything into one
        # running `ans` variable as the optimal solution does.
        gaps = [b - a for a, b in zip(nums, nums[1:])]
        run_end = [1] * n
        run_begin = [1] * n
        for i in range(1, n):
            run_end[i] = 2 if i == 1 or gaps[i-1] != gaps[i-2] else run_end[i-1] + 1
        for i in range(n - 2, -1, -1):
            run_begin[i] = 2 if i == n - 2 or gaps[i] != gaps[i+1] else run_begin[i+1] + 1
        candidates = list(run_end)
        for i in range(n):
            if i - 1 >= 0:
                candidates.append(run_end[i-1] + 1)
            if i + 1 <= n - 1:
                candidates.append(run_begin[i+1] + 1)
            if 0 < i < n - 1 and (nums[i+1] - nums[i-1]) % 2 == 0:
                need = (nums[i+1] - nums[i-1]) // 2
                left_part = run_end[i-1] if (i - 1 > 0 and gaps[i-2] == need) else 1
                right_part = run_begin[i+1] if (i + 1 < n - 1 and gaps[i+1] == need) else 1
                candidates.append(left_part + 1 + right_part)
        return min(max(candidates), n)

