class Solution:
    def longestArithmetic(self, nums):
        n = len(nums)
        if n <= 2:
            return n
        diff = [nums[i+1] - nums[i] for i in range(n - 1)]
        L = [1] * n
        for i in range(1, n):
            if i == 1:
                L[i] = 2
            else:
                L[i] = L[i-1] + 1 if diff[i-1] == diff[i-2] else 2
        R = [1] * n
        for i in range(n - 2, -1, -1):
            if i == n - 2:
                R[i] = 2
            else:
                R[i] = R[i+1] + 1 if diff[i] == diff[i+1] else 2
        ans = max(L)
        for i in range(n):
            if i >= 1:
                ans = max(ans, L[i-1] + 1)
            if i <= n - 2:
                ans = max(ans, R[i+1] + 1)
            if 1 <= i <= n - 2 and (nums[i-1] + nums[i+1]) % 2 == 0:
                d = (nums[i+1] - nums[i-1]) // 2
                leftc = L[i-1] if (i - 1 >= 1 and diff[i-2] == d) else 1
                rightc = R[i+1] if (i + 1 <= n - 2 and diff[i+1] == d) else 1
                ans = max(ans, leftc + 1 + rightc)
        return min(ans, n)

