var longestArithmetic = function(nums) {
    const n = nums.length;
    if (n <= 2) return n;
    const diff = new Array(n - 1);
    for (let i = 0; i < n - 1; i++) diff[i] = nums[i+1] - nums[i];
    const L = new Array(n).fill(1);
    for (let i = 1; i < n; i++) {
        if (i === 1) L[i] = 2;
        else L[i] = diff[i-1] === diff[i-2] ? L[i-1] + 1 : 2;
    }
    const R = new Array(n).fill(1);
    for (let i = n - 2; i >= 0; i--) {
        if (i === n - 2) R[i] = 2;
        else R[i] = diff[i] === diff[i+1] ? R[i+1] + 1 : 2;
    }
    let ans = Math.max(...L);
    for (let i = 0; i < n; i++) {
        if (i >= 1) ans = Math.max(ans, L[i-1] + 1);
        if (i <= n - 2) ans = Math.max(ans, R[i+1] + 1);
        if (i >= 1 && i <= n - 2 && (nums[i-1] + nums[i+1]) % 2 === 0) {
            const d = (nums[i+1] - nums[i-1]) / 2;
            const leftc = (i - 1 >= 1 && diff[i-2] === d) ? L[i-1] : 1;
            const rightc = (i + 1 <= n - 2 && diff[i+1] === d) ? R[i+1] : 1;
            ans = Math.max(ans, leftc + 1 + rightc);
        }
    }
    return Math.min(ans, n);
};
